mapper.update:
UPDATE MEMBERS
	SET EXPERIENCE = EXPERIENCE + #{amount}
WHERE USER_ID = #{userId}

UPDATE MEMBERS
	SET USER_LEVEL = #{level}
WHERE USER_ID = #{userId}

UPDATE MEMBERS
SET CONSEC_DAYS = CONSEC_DAYS + 1
WHERE USER_ID = #{userId}

UPDATE MEMBER_ACHIEVEMENT
SET IS_REWARDED = 'Y'
WHERE USER_ID = #{userId}
	AND ACHIEVEMENT_ID = #{achievementId}
	AND IS_REWARDED = 'N'
